mapper.select:
SELECT r.id, r.product_id, p.product_name, r.user_id, u.name AS user_name, r.writer_type, r.rating, r.content, r.status, (SELECT COUNT(*) FROM review_comments rc WHERE rc.review_id = r.id) AS comment_count, r.created_at, r.updated_at FROM reviews r JOIN users u ON r.user_id = u.user_id JOIN products p ON r.product_id = p.product_id WHERE 1=1
AND r.status = #{status}
AND r.writer_type = #{writerType}
AND (u.name LIKE '%' || #{keyword} || '%' OR p.product_name LIKE '%' || #{keyword} || '%' OR r.content LIKE '%' || #{keyword} || '%')
ORDER BY r.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM reviews r JOIN users u ON r.user_id = u.user_id JOIN products p ON r.product_id = p.product_id WHERE 1=1
AND r.status = #{status}
AND r.writer_type = #{writerType}
AND (u.name LIKE '%' || #{keyword} || '%' OR p.product_name LIKE '%' || #{keyword} || '%' OR r.content LIKE '%' || #{keyword} || '%')

mapper.update:
UPDATE reviews
SET writer_type = #{writerType}, rating = #{rating}, content = #{content}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
